import React, { useMemo } from "react";
import {
  formatTokenBalance,
  type UserAssetDatum,
} from "@avail-project/nexus-core";
import Decimal from "decimal.js";

interface AmountInputUnifiedProps {
  amount: string;
  onChange: (value: string) => void;
  onCommit?: (value: string) => void;
  disabled?: boolean;
  maxAvailableAmount?: string;
  unifiedBalances?: UserAssetDatum[];
  tokenIcon?: React.ReactNode;
  usdValue?: string;
  /** Label shown beside Balance text, e.g. "USDC" */
  tokenSymbol?: string;
  header?: React.ReactNode;
}

export function AmountInputUnified({
  amount,
  onChange,
  onCommit,
  disabled,
  maxAvailableAmount,
  unifiedBalances,
  tokenIcon,
  usdValue,
  tokenSymbol,
  header,
}: AmountInputUnifiedProps) {
  const handleMax = () => {
    if (!totalBalance) return;
    onChange(totalBalance);
    onCommit?.(totalBalance);
  };

  const totalBalance = useMemo(() => {
    if (!unifiedBalances || !unifiedBalances.length) return "0";
    return unifiedBalances
      .reduce((acc, curr) => acc.add(curr.balanceInFiat), new Decimal(0))
      .toDecimalPlaces(2)
      .toFixed();
  }, [unifiedBalances]);

  return (
    <div
      className="w-full flex flex-col bg-white min-h-[200px]"
      style={{
        borderRadius: "12px",
        border: "1px solid var(--border-default, #E8E8E7)",
        boxShadow: "0px 1px 12px 0px #5B5B5B0D",
        background: "#FFFFFF",
      }}
    >
      {header && (
        <div className="w-full border-b border-[#E8E8E7] px-5 py-4">
          {header}
        </div>
      )}
      <div className="flex-1 w-full flex flex-col items-center justify-center p-5 relative">
      {/* Central Input row: large amount + MAX button inline */}
      <div className="flex items-center justify-center w-full gap-x-3 mb-2">
        <div
          className="flex items-center justify-center text-center"
          style={{
            fontSize: "40px",
            fontWeight: 500,
            gap: "2px",
          }}
        >
          {tokenIcon ? (
            <div className="flex items-center justify-center mr-4">
              {tokenIcon}
            </div>
          ) : (
            <span className="leading-none text-gray-800 mr-2">$</span>
          )}
          <input
            type="text"
            inputMode="decimal"
            placeholder="0"
            className="min-w-0 text-start bg-transparent border-none outline-none p-0 focus:ring-0 placeholder:text-gray-300 truncate tabular-nums"
            style={{
              fontFamily: "'Delight', sans-serif",
              fontWeight: 500,
              fontSize: "40px",
              lineHeight: "100%",
              height: "40px",
              letterSpacing: "2%",
              color: "var(--foreground-primary, #161615)",
              fieldSizing: "content",
              minWidth: "1ch",
              maxWidth: "6ch",
            }}
            value={amount}
            disabled={disabled}
            onChange={(e) => {
              let next = e.target.value.replaceAll(/[^0-9.]/g, "");
              const parts = next.split(".");
              if (parts.length > 2)
                next = parts[0] + "." + parts.slice(1).join("");
              if (next === ".") next = "0.";
              onChange(next);
            }}
            onBlur={() => onCommit?.(amount)}
            onKeyDown={(e) => {
              if (e.key === "Enter") onCommit?.(amount);
            }}
          />
        </div>
        {/* MAX button — inline beside the input */}
        <button
          onClick={handleMax}
          disabled={disabled || !maxAvailableAmount}
          className="shrink-0 focus:opacity-80 disabled:opacity-40 disabled:cursor-not-allowed transition-opacity"
          style={{
            background: "var(--background-tertiary, #F0F0EF)",
            width: "44px",
            height: "26px",
            borderRadius: "6px",
            padding: "4px 8px",
            color: "var(--foreground-muted, #848483)",
            fontFamily:
              "var(--font-geist-mono), ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace",
            fontWeight: 400,
            fontSize: "12px",
            lineHeight: "100%",
          }}
        >
          MAX
        </button>
      </div>

      {/* Balance display — below amount + MAX row */}
      {(totalBalance || maxAvailableAmount) && (
        <div className="absolute bottom-5 left-0 w-full flex justify-center">
          <p
            style={{
              color: "var(--widget-card-foreground-muted, #848483)",
              fontFamily:
                "var(--font-geist-sans), ui-sans-serif, system-ui, sans-serif",
              fontWeight: 400,
              fontSize: "13px",
              lineHeight: "100%",
              textAlign: "center",
            }}
          >
            Balance: {totalBalance ? `$${totalBalance}` : `$0`}
          </p>
        </div>
      )}
      </div>
    </div>
  );
}

import React, { useState } from "react";
import { type SwapTokenOption } from "./swap-asset-selector";

interface DepositIdleFormProps {
  amount: string;
  onAmountChange: (val: string) => void;
  toToken?: SwapTokenOption;
  totalBalance: string;
  usdValue: string;
  fromTokens: SwapTokenOption[];
  onOpenSourcePicker: () => void;
  onSetPercent: (pct: number) => void;
}

export function DepositIdleForm({
  amount,
  onAmountChange,
  toToken,
  totalBalance,
  usdValue,
  fromTokens,
  onOpenSourcePicker,
  onSetPercent,
}: DepositIdleFormProps) {
  const handleInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    let next = e.target.value.replaceAll(/[^0-9.]/g, "");
    const parts = next.split(".");
    if (parts.length > 2) next = parts[0] + "." + parts.slice(1).join("");
    if (next === ".") next = "0.";
    onAmountChange(next);
  };

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: "16px", width: "100%" }}>

      {/* ─── DEPOSIT AMOUNT PANEL ─── */}
      <div
        style={{
          alignItems: "center",
          backgroundColor: "#FFFFFE",
          borderColor: "#E8E8E7",
          borderRadius: "12px",
          borderStyle: "solid",
          borderWidth: "1px",
          boxShadow: "#1616150A 0px 1px 2px",
          boxSizing: "border-box",
          display: "flex",
          flexDirection: "column",
          gap: "12px",
          justifyContent: "center",
          paddingBlock: "20px",
          paddingInline: "16px",
        }}
      >
        {/* Header row: Deposit + Total Balance */}
        <div style={{ alignItems: "center", alignSelf: "stretch", boxSizing: "border-box", display: "flex", justifyContent: "space-between" }}>
          <div style={{ boxSizing: "border-box", color: "#848483", fontFamily: '"Geist", system-ui, sans-serif', fontSize: "12px", fontWeight: 500, letterSpacing: "0.08em", lineHeight: "20px", textTransform: "uppercase" }}>
            Deposit
          </div>
          <div style={{ alignItems: "center", boxSizing: "border-box", display: "flex", gap: "4px" }}>
            <div style={{ boxSizing: "border-box", color: "#848483", fontFamily: '"Geist", system-ui, sans-serif', fontSize: "14px", lineHeight: "20px" }}>
              Total Balance:
            </div>
            <div style={{ boxSizing: "border-box", color: "#848483", fontFamily: '"Geist", system-ui, sans-serif', fontSize: "14px", lineHeight: "20px" }}>
              ${totalBalance}
            </div>
          </div>
        </div>

        {/* Amount + Token pill */}
        <div style={{ alignSelf: "stretch", boxSizing: "border-box", display: "flex", flexDirection: "column", gap: "8px" }}>
          <div style={{ alignItems: "center", boxSizing: "border-box", display: "flex", gap: "10px", justifyContent: "space-between", width: "100%" }}>
            <input
              type="text"
              placeholder="0"
              value={amount}
              onChange={handleInput}
              style={{
                boxSizing: "border-box",
                color: amount ? "#161615" : "#9E9E9C",
                fontFamily: '"Delight-Medium", "Delight", system-ui, sans-serif',
                fontSize: "36px",
                fontWeight: 500,
                lineHeight: "44px",
                background: "transparent",
                border: "none",
                outline: "none",
                padding: 0,
                width: "100%",
                minWidth: 0,
              }}
            />

            {/* Token pill (non-clickable, shows fixed deposit token) */}
            <div
              style={{
                alignItems: "center",
                backgroundColor: "#FFFFFE",
                borderColor: "#E8E8E7",
                borderRadius: "999px",
                borderStyle: "solid",
                borderWidth: "1px",
                boxShadow: "#1616150A 0px 1px 2px",
                boxSizing: "border-box",
                display: "inline-flex",
                flexShrink: 0,
                gap: "8px",
                height: "36px",
                paddingLeft: "4px",
                paddingRight: "10px",
              }}
            >
              {toToken?.logo ? (
                <div style={{ boxSizing: "border-box", flexShrink: 0, height: "26px", position: "relative", width: "26px" }}>
                  <img src={toToken.logo} alt={toToken.symbol} style={{ borderRadius: "999px", height: "26px", width: "26px", objectFit: "cover" }} />
                  {toToken.chainLogo && (
                    <img src={toToken.chainLogo} alt={toToken.chainName} style={{ borderRadius: "999px", bottom: -2, height: "12px", outline: "1px solid #FFFFFE", position: "absolute", right: -2, width: "12px", objectFit: "cover" }} />
                  )}
                </div>
              ) : (
                <div style={{ width: "26px", height: "26px", borderRadius: "999px", backgroundColor: "#F0F0EF", flexShrink: 0 }} />
              )}
              <div style={{ boxSizing: "border-box", color: "#161615", fontFamily: '"Geist", system-ui, sans-serif', fontSize: "16px", fontWeight: 500, lineHeight: "24px" }}>
                {toToken?.symbol || "Token"}
              </div>
            </div>
          </div>

          {/* USD and balance row */}
          <div style={{ alignItems: "center", boxSizing: "border-box", display: "flex", justifyContent: "space-between" }}>
            <div style={{ boxSizing: "border-box", color: "#848483", fontFamily: '"Geist", system-ui, sans-serif', fontSize: "14px", lineHeight: "20px" }}>
              ≈ ${usdValue || "0.00"}
            </div>
            <div style={{ alignItems: "center", boxSizing: "border-box", display: "flex", gap: "5px" }}>
              <div style={{ boxSizing: "border-box", color: "#7C7C7A", fontFamily: '"Geist", system-ui, sans-serif', fontSize: "14px", lineHeight: "20px" }}>
                Balance:
              </div>
              <div style={{ boxSizing: "border-box", color: "#161615", fontFamily: '"Geist", system-ui, sans-serif', fontSize: "14px", fontWeight: 500, lineHeight: "20px" }}>
                {toToken?.balance || "0"} {toToken?.symbol || ""}
              </div>
            </div>
          </div>

          {/* 25% 50% 75% MAX quick buttons */}
          <div style={{ alignItems: "center", boxSizing: "border-box", display: "flex", gap: "6px", width: "100%" }}>
            {[25, 50, 75].map(pct => (
              <button
                key={pct}
                onClick={() => onSetPercent(pct)}
                style={{
                  alignItems: "center", backgroundColor: "#F4F4F3", borderRadius: "8px", boxSizing: "border-box", display: "flex", flex: "1 1 0%", justifyContent: "center", paddingBlock: "5px", paddingInline: "10px", border: "none", cursor: "pointer",
                }}
              >
                <div style={{ boxSizing: "border-box", color: "#363635", fontFamily: '"Geist", system-ui, sans-serif', fontSize: "12px", fontWeight: 500, lineHeight: "20px" }}>
                  {pct}%
                </div>
              </button>
            ))}
            <button
              onClick={() => onSetPercent(100)}
              style={{
                alignItems: "center", backgroundColor: "#E8F0FF", borderRadius: "8px", boxSizing: "border-box", display: "flex", flex: "1 1 0%", justifyContent: "center", paddingBlock: "5px", paddingInline: "10px", border: "none", cursor: "pointer",
              }}
            >
              <div style={{ boxSizing: "border-box", color: "#006BF4", fontFamily: '"Geist", system-ui, sans-serif', fontSize: "12px", fontWeight: 500, letterSpacing: "0.02em", lineHeight: "20px" }}>
                MAX
              </div>
            </button>
          </div>
        </div>

        {/* Add asset button */}
        <button
          onClick={onOpenSourcePicker}
          style={{
            alignItems: "center",
            alignSelf: "stretch",
            backgroundColor: "#F4F7FE",
            borderRadius: "8px",
            boxSizing: "border-box",
            display: "flex",
            gap: "6px",
            justifyContent: "center",
            paddingBlock: "9px",
            paddingInline: "9px",
            border: "none",
            cursor: "pointer",
          }}
        >
          <svg width="12" height="12" viewBox="0 0 12 12" xmlns="http://www.w3.org/2000/svg" style={{ flexShrink: 0 }}>
            <path d="M6 2V10M2 6H10" stroke="#006BF4" strokeWidth="1.5" strokeLinecap="round" />
          </svg>
          <div style={{ boxSizing: "border-box", color: "#006BF4", fontFamily: '"Geist", system-ui, sans-serif', fontSize: "12px", fontWeight: 500, lineHeight: "20px" }}>
            {fromTokens.length > 0 ? `${fromTokens.length} source${fromTokens.length > 1 ? "s" : ""} selected` : "Add asset"}
          </div>
        </button>
      </div>
    </div>
  );
}

"use client";
import React from "react";
import { type DepositOpportunity } from "../types";

interface OpportunityListProps {
  opportunities: DepositOpportunity[];
  selectedId?: string;
  onSelect: (opportunity: DepositOpportunity) => void;
}

export function OpportunityList({ opportunities, selectedId, onSelect }: OpportunityListProps) {
  if (!opportunities || opportunities.length === 0) {
    return (
      <div style={{ width: "100%", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", paddingBlock: "32px", gap: "8px" }}>
        <p style={{ fontFamily: '"Geist", system-ui, sans-serif', fontSize: "14px", color: "#848483" }}>
          No opportunities configured
        </p>
      </div>
    );
  }

  return (
    <div
      style={{
        alignSelf: "stretch",
        backgroundColor: "#FFFFFE",
        borderColor: "#E8E8E7",
        borderRadius: "14px",
        borderStyle: "solid",
        borderWidth: "1px",
        boxShadow: "#5B5B5B0D 0px 1px 12px",
        boxSizing: "border-box",
        display: "flex",
        flex: 1,
        flexDirection: "column",
        overflow: "clip",
      }}
    >
      {opportunities.map((opp, idx) => {
        const isSelected = selectedId === opp.id;
        const isLast = idx === opportunities.length - 1;

        return (
          <button
            key={opp.id}
            onClick={() => onSelect(opp)}
            style={{
              alignItems: "center",
              backgroundColor: "#FFFFFE",
              borderBottomColor: isLast ? "transparent" : "#F0F0EF",
              borderBottomStyle: "solid",
              borderBottomWidth: isLast ? "0px" : "1px",
              borderTop: "none",
              borderLeft: "none",
              borderRight: "none",
              boxSizing: "border-box",
              display: "flex",
              gap: "12px",
              paddingBlock: "14px",
              paddingInline: "16px",
              cursor: "pointer",
              width: "100%",
              textAlign: "left",
            }}
          >
            {/* Radio button */}
            <div
              style={{
                alignItems: "center",
                backgroundColor: "#FFFFFE",
                borderColor: isSelected ? "#006BF4" : "#D0D0CF",
                borderRadius: "999px",
                borderStyle: "solid",
                borderWidth: "2px",
                boxSizing: "border-box",
                display: "flex",
                flexShrink: 0,
                height: "20px",
                justifyContent: "center",
                width: "20px",
              }}
            >
              {isSelected && (
                <div
                  style={{
                    backgroundColor: "#006BF4",
                    borderRadius: "999px",
                    height: "10px",
                    width: "10px",
                  }}
                />
              )}
            </div>

            {/* Logo */}
            <div
              style={{
                alignItems: "center",
                borderRadius: "999px",
                boxSizing: "border-box",
                display: "flex",
                flexShrink: 0,
                height: "36px",
                justifyContent: "center",
                overflow: "clip",
                width: "36px",
              }}
            >
              {opp.logo ? (
                <img
                  src={opp.logo}
                  alt={opp.title || opp.protocol}
                  style={{
                    flexShrink: 0,
                    height: "36px",
                    width: "36px",
                    objectFit: "cover",
                  }}
                  onError={(e) => {
                    (e.target as HTMLImageElement).style.display = "none";
                  }}
                />
              ) : (
                <div
                  style={{
                    width: "36px",
                    height: "36px",
                    borderRadius: "999px",
                    backgroundColor: "#F0F0EF",
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "center",
                    fontFamily: '"Geist", system-ui, sans-serif',
                    fontSize: "14px",
                    fontWeight: 600,
                    color: "#848483",
                  }}
                >
                  {(opp.title || opp.protocol).slice(0, 2)}
                </div>
              )}
            </div>

            {/* Info */}
            <div
              style={{
                boxSizing: "border-box",
                display: "flex",
                flex: "1 1 0%",
                flexDirection: "column",
                gap: "3px",
              }}
            >
              <div style={{ alignItems: "center", boxSizing: "border-box", display: "flex", gap: "6px" }}>
                <div style={{ boxSizing: "border-box", color: "#161615", fontFamily: '"Geist", system-ui, sans-serif', fontSize: "16px", fontWeight: 500, lineHeight: "18px" }}>
                  {opp.title || opp.protocol}
                </div>
              </div>
              {(opp.subtitle || opp.description) && (
                <div style={{ boxSizing: "border-box", color: "#848483", fontFamily: '"Geist", system-ui, sans-serif', fontSize: "14px", lineHeight: "16px" }}>
                  {opp.subtitle || opp.description}
                </div>
              )}
            </div>
          </button>
        );
      })}
    </div>
  );
}

import { nexusOneTheme } from "../theme";
import React from "react";
import { Pencil, Settings } from "lucide-react";

export interface PayUsingSelectorProps {
  label?: string;
  sublabel?: string;
  onClick?: () => void;
  disabled?: boolean;
  hasSources?: boolean;
}

export function PayUsingSelector({
  label = "Paying with",
  sublabel = "Auto-selected based on amount",
  onClick,
  disabled = false,
  hasSources = false,
}: PayUsingSelectorProps) {
  const isInteractiveRow = !hasSources;

  const content = (
    <>
      <div className="flex items-center gap-x-3">
        <div
          className="flex items-center justify-center w-8 h-8 rounded-full shrink-0"
          style={{
            background: "var(--background-tertiary, var(--background-tertiary, #F0F0EF))",
          }}
        >
          <Settings className="w-4 h-4 text-gray-500" />
        </div>
        <div className="flex flex-col gap-y-0.5 text-left">
          <span
            style={{
              fontFamily: "var(--font-geist-sans), sans-serif",
              fontWeight: 500,
              fontSize: "13px",
              color: "var(--foreground-primary, var(--foreground-primary, #161615))",
            }}
          >
            {label}
          </span>
          <span
            style={{
              fontFamily: "var(--font-geist-sans), sans-serif",
              fontSize: "11px",
              color: "var(--foreground-muted, var(--foreground-muted, #848483))",
            }}
          >
            {sublabel}
          </span>
        </div>
      </div>

      {/* Edit button */}
      {!isInteractiveRow && (
        <button
          onClick={(e) => {
            e.stopPropagation();
            onClick?.();
          }}
          disabled={disabled}
          className="flex items-center gap-x-1.5 px-2.5 py-1.5 rounded-lg hover:bg-black/5 transition-colors disabled:opacity-40 disabled:cursor-not-allowed"
          style={{
            fontFamily: "var(--font-geist-sans), sans-serif",
            fontSize: "12px",
            fontWeight: 500,
            color: "var(--interactive-button-primary-background, var(--foreground-brand, #006BF4))",
          }}
        >
          <Pencil className="w-3 h-3" />
          Edit
        </button>
      )}
    </>
  );

  return (
    <div className="w-full">
      {isInteractiveRow ? (
        <button
          onClick={onClick}
          disabled={disabled}
          className="w-full flex items-center justify-between px-4 py-3 disabled:opacity-50 disabled:cursor-not-allowed transition-all hover:bg-black/5"
          style={{
            background: "var(--background-secondary, #F5F5F4)",
            borderRadius: "12px",
            border: "1px solid var(--border-default, var(--border-default, #E8E8E7))",
          }}
        >
          {content}
        </button>
      ) : (
        <div
          className="w-full flex items-center justify-between px-4 py-3"
          style={{
            background: "var(--background-secondary, #F5F5F4)",
            borderRadius: "12px",
            border: "1px solid var(--border-default, var(--border-default, #E8E8E7))",
          }}
        >
          {content}
        </div>
      )}
    </div>
  );
}

"use client";
import { nexusOneTheme } from "../theme";
import React, { useState, useMemo, useEffect } from "react";
import { createPortal } from "react-dom";
import { Search, X, ChevronDown, Check, Info, Copy } from "lucide-react";
import { type SwapTokenOption } from "./swap-asset-selector";
import { useNexus } from "../../nexus/NexusProvider";
import { RadioDot } from "./swap-asset-selector";
import { CHAIN_METADATA, formatTokenBalance } from "@avail-project/nexus-core";

interface ReceiveAssetSelectorProps {
  onSelect: (token: SwapTokenOption) => void;
  onBack: () => void;
}

const SUPPORTED_RECEIVE_CHAIN_IDS = new Set([1, 10, 56, 137, 143, 999, 8217, 8453, 42161, 43114, 534352, 4114]);

const AVATAR_COLORS = [
  "#FF6B6B", "#4ECDC4", "#45B7D1", "#96CEB4", "#D4A5A5", 
  "#9B59B6", "#3498DB", "#E67E22", "#1ABC9C", "#F39C12", "#34495E"
];

const getAvatarColor = (str: string) => {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = str.charCodeAt(i) + ((hash << 5) - hash);
  }
  return AVATAR_COLORS[Math.abs(hash) % AVATAR_COLORS.length];
};

const TokenLogo = ({ token, size = 40, fontSize = 16 }: { token: SwapTokenOption, size?: number, fontSize?: number }) => {
  const [error, setError] = useState(false);

  if (!token.logo || error) {
    return (
      <div style={{ position: "absolute", inset: 0, borderRadius: "999px", display: "flex", alignItems: "center", justifyContent: "center", backgroundColor: getAvatarColor(token.symbol), color: "#fff", fontWeight: 600, fontSize }}>
        {token.symbol.charAt(0).toUpperCase()}
      </div>
    );
  }

  return (
    <img 
      src={token.logo} 
      alt={token.symbol} 
      style={{ position: "absolute", inset: 0, width: size, height: size, borderRadius: "999px", objectFit: "cover" }} 
      onError={() => setError(true)} 
    />
  );
};

const STABLE_SYMBOLS = new Set([
  "USDC", "USDT", "DAI", "FRAX", "LUSD", "TUSD", "USDD", "GHO", "crvUSD", "sUSD", "USDe"
]);

const FILTER_TABS = [
  { label: "All", key: "all" },
  { label: "Native", key: "native" },
  { label: "Stables", key: "stables" },
];

const getTokenBalanceKey = (chainId?: number, address?: string) => {
  if (!chainId || !address) return null;
  return `${chainId}-${address.toLowerCase()}`;
};

const getNativeAddressAlias = (address?: string) => {
  if (!address) return null;
  const lower = address.toLowerCase();
  if (lower === "0xeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeee") {
    return "0x0000000000000000000000000000000000000000";
  }
  if (lower === "0x0000000000000000000000000000000000000000") {
    return "0xeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeee";
  }
  return null;
};

let rawTokensCache: any = null;
let rawTokensPromise: Promise<any> | null = null;

export const preloadReceiveTokens = () => {
  if (typeof window === "undefined") return null;
  if (!rawTokensPromise) {
    rawTokensPromise = (async () => {
      const CACHE_KEY = "nexus_receive_tokens_cache_v2";
      const CACHE_TIME_KEY = "nexus_receive_tokens_time_v2";

      try {
        const cachedTime = localStorage.getItem(CACHE_TIME_KEY);
        const cachedData = localStorage.getItem(CACHE_KEY);
        if (cachedTime && cachedData && Date.now() - Number(cachedTime) < 24 * 60 * 60 * 1000) {
          const data = JSON.parse(cachedData);
          rawTokensCache = data;
          return data;
        }
      } catch (err) {}

      let data: any = { tokens: {}, stableSymbols: [] };
      try {
        const [resAll, resStables] = await Promise.all([
          fetch("https://li.quest/v1/tokens"),
          fetch("https://li.quest/v1/tokens?tags=stablecoin")
        ]);

        let allTokens = {};
        if (resAll.ok) {
          const allData = await resAll.json();
          allTokens = allData.tokens || {};
        }

        const stableSymbols = new Set<string>();
        if (resStables.ok) {
          const stablesData = await resStables.json();
          const stableChains = stablesData.tokens || {};
          for (const chainId of Object.keys(stableChains)) {
            for (const t of stableChains[chainId]) {
              stableSymbols.add(t.symbol);
            }
          }
        }

        data = {
          tokens: allTokens,
          stableSymbols: Array.from(stableSymbols)
        };
      } catch (err) {
        console.error("Failed to fetch tokens from li.quest", err);
      }

      rawTokensCache = data;

      try {
        localStorage.setItem(CACHE_KEY, JSON.stringify(data));
        localStorage.setItem(CACHE_TIME_KEY, Date.now().toString());
      } catch (err) {}

      return data;
    })();
  }
  return rawTokensPromise;
};

// Start preloading immediately in the background
if (typeof window !== "undefined") {
  setTimeout(() => {
    preloadReceiveTokens();
  }, 1000);
}

export function ReceiveAssetSelector({
  onSelect,
  onBack,
}: ReceiveAssetSelectorProps) {
  const { supportedChainsAndTokens, swapBalance } = useNexus();
  const [query, setQuery] = useState("");
  const [activeTab, setActiveTab] = useState("all");
  const [selectedChainFilter, setSelectedChainFilter] = useState<number | null>(null);
  const [showChainSelector, setShowChainSelector] = useState(false);
  const [selectedTokenHash, setSelectedTokenHash] = useState<string | null>(null);
  const [selectedTokenFull, setSelectedTokenFull] = useState<SwapTokenOption | null>(null);
  const [hoveredHash, setHoveredHash] = useState<string | null>(null);
  const [copiedHash, setCopiedHash] = useState<string | null>(null);
  const [visibleCount, setVisibleCount] = useState(30);
  const [tooltipState, setTooltipState] = useState<{ x: number, y: number, t: SwapTokenOption } | null>(null);
  const hoverTimeoutRef = React.useRef<NodeJS.Timeout | null>(null);

  const [apiTokens, setApiTokens] = useState<SwapTokenOption[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [dynamicStableSymbols, setDynamicStableSymbols] = useState<Set<string>>(STABLE_SYMBOLS);

  const balanceMap = useMemo(() => {
    const map = new Map<string, Pick<SwapTokenOption, "balance" | "balanceInFiat">>();
    for (const asset of swapBalance ?? []) {
      for (const bd of asset.breakdown ?? []) {
        const key = getTokenBalanceKey(bd.chain?.id, bd.contractAddress);
        if (!key) continue;

        const symbol = bd.symbol ?? asset.symbol;
        const decimals = bd.decimals ?? asset.decimals ?? 18;
        map.set(key, {
          balance:
            formatTokenBalance(bd.balance ?? "0", {
              symbol,
              decimals,
            }) ?? `0 ${symbol}`,
          balanceInFiat:
            bd.balanceInFiat != null
              ? `$${Number(bd.balanceInFiat).toFixed(2)}`
              : "$0.00",
        });
        const nativeAlias = getNativeAddressAlias(bd.contractAddress);
        const aliasKey = getTokenBalanceKey(bd.chain?.id, nativeAlias ?? undefined);
        if (aliasKey) {
          map.set(aliasKey, map.get(key)!);
        }
      }
    }
    return map;
  }, [swapBalance]);

  const tokensWithBalances = useMemo(() => {
    return apiTokens.map((token) => {
      const balance = balanceMap.get(
        getTokenBalanceKey(token.chainId, token.contractAddress) ?? "",
      );
      return balance ? { ...token, ...balance } : token;
    });
  }, [apiTokens, balanceMap]);

  useEffect(() => {
    const handleGlobalClick = () => setTooltipState(null);
    if (tooltipState) {
      window.addEventListener("click", handleGlobalClick);
      window.addEventListener("touchstart", handleGlobalClick);
    }
    return () => {
      window.removeEventListener("click", handleGlobalClick);
      window.removeEventListener("touchstart", handleGlobalClick);
    };
  }, [tooltipState]);

  // Reset visible count when filters change
  useEffect(() => {
    setVisibleCount(30);
  }, [query, activeTab, selectedChainFilter]);

  // Cross-reference map for chain names & logos, and balances
  const chainMetaMap = useMemo(() => {
    const map = new Map<number, { name: string; logo: string }>();
    if (supportedChainsAndTokens) {
      for (const c of supportedChainsAndTokens) {
        map.set(c.id, { name: c.name, logo: c.logo });
      }
    }
    return map;
  }, [supportedChainsAndTokens]);

  useEffect(() => {
    let active = true;
    const fetchTokens = async () => {
      try {
        setIsLoading(true);
        preloadReceiveTokens();

        const data = await rawTokensPromise;
        if (!active) return;

        if (data.stableSymbols && Array.isArray(data.stableSymbols)) {
          setDynamicStableSymbols(new Set([...Array.from(STABLE_SYMBOLS), ...data.stableSymbols]));
        }

        const allParsed: SwapTokenOption[] = [];
        const chains = data.tokens || {};
        for (const chainIdStr of Object.keys(chains)) {
          const chainId = parseInt(chainIdStr, 10);
          if (!SUPPORTED_RECEIVE_CHAIN_IDS.has(chainId)) continue;
          const meta = chainMetaMap.get(chainId) || { name: `Chain ${chainId}`, logo: "" };
          for (const t of chains[chainIdStr]) {
            allParsed.push({
              contractAddress: t.address,
              symbol: t.symbol,
              name: t.name,
              logo: t.logoURI || "",
              decimals: t.decimals,
              chainId,
              chainName: meta.name,
              chainLogo: meta.logo,
              balance: "0",
              balanceInFiat: "$0.00",
            });
          }
        }
        setApiTokens(allParsed);
      } catch (err) {
        console.error("Failed to fetch receive tokens", err);
      } finally {
        if (active) setIsLoading(false);
      }
    };
    fetchTokens();
    return () => { active = false; };
  }, [chainMetaMap]);

  const isNativeToken = (t: SwapTokenOption) =>
    t.contractAddress.toLowerCase() === "0xeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeee" ||
    t.contractAddress === "0x0000000000000000000000000000000000000000";

  const filtered = useMemo(() => {
    let result = tokensWithBalances;
    if (selectedChainFilter) result = result.filter(t => t.chainId === selectedChainFilter);
    if (query.trim()) {
      const terms = query.toLowerCase().split(/\s+/).filter(Boolean);
      result = result.filter(t => {
        const targetStr = `${t.symbol} ${t.name} ${t.chainName} ${t.contractAddress}`.toLowerCase();
        return terms.every(term => targetStr.includes(term));
      });
    }
    if (activeTab === "native") result = result.filter(isNativeToken);
    else if (activeTab === "stables") result = result.filter(t => dynamicStableSymbols.has(t.symbol));

    return result;
  }, [tokensWithBalances, selectedChainFilter, query, activeTab, dynamicStableSymbols]);

  return (
    <div style={{ display: "flex", flexDirection: "column", flex: 1, minHeight: 0, width: "100%", position: "relative" }}>
      <div style={{ padding: "0 16px 16px", display: "flex", flexDirection: "column", gap: 12, position: "relative", zIndex: 10 }}>

        {/* Search */}
        <div style={{ display: "flex", alignItems: "center", height: 44, gap: 8, borderRadius: 12, border: "1px solid #E8E8E7", padding: "0 8px 0 16px", backgroundColor: "#F0F0EF" }}>
          <Search style={{ width: 20, height: 20, color: "#848483", flexShrink: 0 }} />
          <input
            value={query} onChange={(e) => setQuery(e.target.value)}
            placeholder="Search token, chain or address"
            style={{ flex: 1, backgroundColor: "transparent", border: "none", outline: "none", fontFamily: '"Geist", system-ui, sans-serif', fontSize: 14, color: "#161615", minWidth: 0 }}
          />
          {query && <button onClick={() => setQuery("")} style={{ background: "none", border: "none", cursor: "pointer", padding: 0 }}><X style={{ width: 16, height: 16, color: "#848483" }} /></button>}
          <button 
            onClick={() => setShowChainSelector(true)}
            style={{ display: "flex", alignItems: "center", gap: 4, padding: "4px 8px", borderRadius: 999, backgroundColor: "#FFFFFE", border: "1px solid #E8E8E7", cursor: "pointer", height: 32, flexShrink: 0, boxShadow: "0px 1px 2px rgba(0,0,0,0.05)" }}
          >
            {selectedChainFilter === null ? (
               <img src="/nexus-one/all-chains.png" alt="All Chains" style={{ width: 20, height: 20, borderRadius: "999px", objectFit: "cover" }} />
            ) : (
               <img src={chainMetaMap.get(selectedChainFilter)?.logo} style={{ width: 20, height: 20, borderRadius: "999px", objectFit: "cover" }} />
            )}
            <ChevronDown style={{ width: 14, height: 14, color: "#848483" }} />
          </button>
        </div>

        {/* Filter tabs */}
        <div style={{ display: "flex", gap: 0, backgroundColor: "#F0F0EF", borderRadius: 8, padding: 4 }}>
          {FILTER_TABS.map((tab) => (
            <button
              key={tab.key} onClick={() => setActiveTab(tab.key)}
              style={{
                flex: 1, padding: "6px 0", backgroundColor: activeTab === tab.key ? "#FFFFFE" : "transparent", border: "none",
                borderRadius: 6, cursor: "pointer", fontFamily: '"Geist", system-ui, sans-serif', fontSize: 13, fontWeight: 500,
                color: activeTab === tab.key ? "#161615" : "#848483", boxShadow: activeTab === tab.key ? "0px 1px 2px rgba(0,0,0,0.05)" : "none",
                transition: "all 0.15s",
              }}
            >
              {tab.label}
            </button>
          ))}
        </div>
      </div>

      {/* Token list */}
      <div 
        style={{ flex: 1, overflowY: "auto", position: "relative", zIndex: hoveredHash ? 20 : 1 }}
        onScroll={(e) => {
          const { scrollTop, scrollHeight, clientHeight } = e.currentTarget;
          if (scrollHeight - scrollTop - clientHeight < 200) {
            setVisibleCount(prev => prev + 30);
          }
        }}
      >
        {isLoading ? (
          <div style={{ textAlign: "center", padding: "40px", color: "#848483", fontFamily: '"Geist", system-ui, sans-serif' }}>Loading...</div>
        ) : filtered.length === 0 ? (
          <div style={{ textAlign: "center", padding: "40px", color: "#848483", fontFamily: '"Geist", system-ui, sans-serif' }}>No tokens found</div>
        ) : (
          <div style={{ display: "flex", flexDirection: "column" }}>
            {filtered.slice(0, visibleCount).map(t => {
              const hash = `${t.chainId}-${t.contractAddress}`;
              const isSelected = selectedTokenHash === hash;
              const isHovered = hoveredHash === hash;
              const numericBalance = Number.parseFloat(
                String(t.balance ?? "0").replace(/[^0-9.]/g, ""),
              );
              const hasBalance =
                Number.isFinite(numericBalance) && numericBalance > 0;
              return (
                <button
                  key={hash}
                  onClick={() => { setSelectedTokenHash(hash); setSelectedTokenFull(t); }}
                  onMouseEnter={() => setHoveredHash(hash)}
                  onMouseLeave={() => setHoveredHash(null)}
                  style={{
                    width: "100%", display: "flex", alignItems: "center", justifyContent: "space-between",
                    padding: "12px 16px", backgroundColor: isSelected ? "#F4F7FE" : "transparent", border: "none",
                    cursor: "pointer", borderBottom: "1px solid #F0F0EF", boxSizing: "border-box",
                    position: isHovered ? "relative" : "static",
                    zIndex: isHovered ? 50 : 1
                  }}
                >
                  <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                    <RadioDot selected={isSelected} />
                    <div style={{ position: "relative", flexShrink: 0, width: 40, height: 40 }}>
                      <TokenLogo token={t} size={40} fontSize={16} />
                      {t.chainLogo && <img src={t.chainLogo} alt={t.chainName} style={{ position: "absolute", bottom: -2, right: -2, width: 14, height: 14, borderRadius: "999px", border: "2px solid #FFFFFE", zIndex: 2 }} />}
                    </div>
                    <div style={{ display: "flex", flexDirection: "column", alignItems: "flex-start" }}>
                      <span style={{ fontFamily: '"Geist", system-ui, sans-serif', fontWeight: 500, fontSize: 15, color: "#161615" }}>{t.symbol}</span>
                      <div style={{ display: "flex", alignItems: "center", gap: 4 }}>
                        <span style={{ fontFamily: '"Geist", system-ui, sans-serif', fontSize: 13, color: "#848483" }}>
                          {t.contractAddress.slice(0, 6)}...{t.contractAddress.slice(-4)}
                        </span>
                        {isHovered && (
                        <div style={{ display: "flex", alignItems: "center", gap: "4px" }}>
                          {copiedHash === hash ? (
                            <Check style={{ width: 12, height: 12, color: "#006BF4" }} />
                          ) : (
                            <Copy
                              style={{ width: 12, height: 12, color: "#848483", cursor: "pointer" }}
                              onClick={(e) => { 
                                e.stopPropagation(); 
                                navigator.clipboard.writeText(t.contractAddress); 
                                setCopiedHash(hash);
                                setTimeout(() => setCopiedHash(null), 2000);
                              }}
                            />
                          )}
                          <div 
                            className="relative"
                            onClick={(e) => {
                              e.stopPropagation();
                              if (tooltipState?.t.contractAddress === t.contractAddress) {
                                setTooltipState(null);
                              } else {
                                if (hoverTimeoutRef.current) clearTimeout(hoverTimeoutRef.current);
                                const rect = e.currentTarget.getBoundingClientRect();
                                setTooltipState({ x: rect.left + rect.width / 2, y: rect.top, t });
                              }
                            }}
                            onMouseEnter={(e) => {
                              if (hoverTimeoutRef.current) clearTimeout(hoverTimeoutRef.current);
                              const rect = e.currentTarget.getBoundingClientRect();
                              setTooltipState({ x: rect.left + rect.width / 2, y: rect.top, t });
                            }}
                            onMouseLeave={() => {
                              hoverTimeoutRef.current = setTimeout(() => setTooltipState(null), 150);
                            }}
                          >
                            <Info style={{ width: 12, height: 12, color: "#848483", cursor: "pointer" }} />
                          </div>
                        </div>
                        )}
                      </div>
                    </div>
                  </div>
                  {hasBalance && (
                    <div style={{ display: "flex", flexDirection: "column", alignItems: "flex-end" }}>
                      <span style={{ fontFamily: '"Geist", system-ui, sans-serif', fontWeight: 500, fontSize: 14, color: "#161615" }}>{t.balance}</span>
                      <span style={{ fontFamily: '"Geist", system-ui, sans-serif', fontSize: 13, color: "#848483" }}>{t.balanceInFiat}</span>
                    </div>
                  )}
                </button>
              );
            })}
          </div>
        )}
      </div>

      {/* Done Button Footer */}
      <div style={{ padding: 16, backgroundColor: "#FFFFFE", borderTop: "1px solid #E8E8E7", flexShrink: 0, zIndex: 10 }}>
        <button
          onClick={() => {
            if (selectedTokenFull) onSelect(selectedTokenFull);
          }}
          disabled={!selectedTokenFull}
          style={{
            width: "100%", padding: "12px", borderRadius: 12, backgroundColor: selectedTokenFull ? "#006BF4" : "#C8C8C7",
            color: "#FFFFFE", border: "none", cursor: selectedTokenFull ? "pointer" : "not-allowed",
            fontFamily: '"Geist", system-ui, sans-serif', fontWeight: 600, fontSize: 16
          }}
        >
          Done
        </button>
      </div>

      {/* Chain Selector Modal */}
      {showChainSelector && (
        <div style={{ position: "absolute", top: 0, left: 0, right: 0, bottom: 0, backgroundColor: "#FFFFFE", zIndex: 10, display: "flex", flexDirection: "column" }}>
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: 16, borderBottom: "1px solid #E8E8E7" }}>
            <span style={{ fontFamily: '"Geist", system-ui, sans-serif', fontWeight: 600, fontSize: 18, color: "#161615" }}>Select Chain</span>
            <button onClick={() => setShowChainSelector(false)} style={{ background: "none", border: "none", cursor: "pointer", padding: 4 }}>
              <X style={{ width: 20, height: 20, color: "#848483" }} />
            </button>
          </div>
          <div style={{ flex: 1, overflowY: "auto" }}>
            <button
              onClick={() => { setSelectedChainFilter(null); setShowChainSelector(false); }}
              style={{ width: "100%", display: "flex", alignItems: "center", justifyContent: "space-between", padding: "16px", backgroundColor: "transparent", border: "none", borderBottom: "1px solid #F0F0EF", cursor: "pointer" }}
            >
              <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                <img src="/nexus-one/all-chains.png" style={{ width: 32, height: 32, borderRadius: "999px", objectFit: "cover" }} />
                <span style={{ fontFamily: '"Geist", system-ui, sans-serif', fontWeight: 500, fontSize: 16, color: "#161615" }}>All Chains</span>
              </div>
              {selectedChainFilter === null && <Check style={{ width: 20, height: 20, color: "#006BF4" }} />}
            </button>
            {Array.from(SUPPORTED_RECEIVE_CHAIN_IDS).map(id => {
              const meta = chainMetaMap.get(id);
              if (!meta) return null;
              return (
