    />
  </svg>
);

/** Reusable percentage quick-select buttons row with transition wrapper */
function PercentButtons({
  visible,
  onSelect,
  maxLabel = "MAX",
}: {
  visible: boolean;
  onSelect: (pct: number) => void;
  maxLabel?: string;
}) {
  const [mounted, setMounted] = useState(false);
  const [show, setShow] = useState(false);

  useEffect(() => {
    if (visible) {
      setMounted(true);
      // Trigger the animation on next frame
      requestAnimationFrame(() => {
        requestAnimationFrame(() => setShow(true));
      });
    } else {
      setShow(false);
      const timer = setTimeout(() => setMounted(false), 200);
      return () => clearTimeout(timer);
    }
  }, [visible]);

  if (!mounted) return null;

  return (
    <div
      style={{
        alignItems: "center",
        boxSizing: "border-box",
        display: "flex",
        gap: "6px",
        width: "100%",
        overflow: "hidden",
        maxHeight: show ? "40px" : "0px",
        opacity: show ? 1 : 0,
        marginTop: show ? "0px" : "-4px",
        transition:
          "max-height 0.2s ease-out, opacity 0.2s ease-out, margin-top 0.15s ease-out",
      }}
    >
      {[25, 50, 75, 100].map((pct) => {
        const label = pct === 100 ? maxLabel : `${pct}%`;
        return (
          <PercentHoverButton
            key={pct}
            label={label}
            onClick={() => onSelect(pct)}
          />
        );
      })}
    </div>
  );
}

function PercentHoverButton({
  label,
  onClick,
}: {
  label: string;
  onClick: () => void;
}) {
  const [hover, setHover] = useState(false);
  const [active, setActive] = useState(false);

  const isHighlighted = hover || active;

  return (
    <button
      onMouseEnter={() => setHover(true)}
      onMouseLeave={() => {
        setHover(false);
        setActive(false);
      }}
      onMouseDown={() => setActive(true)}
      onMouseUp={() => setActive(false)}
      onClick={onClick}
      style={{
        alignItems: "center",
        backgroundColor: isHighlighted ? "#E8F0FF" : "#F4F4F3",
        borderRadius: "8px",
        boxSizing: "border-box",
        display: "flex",
        flex: "1 1 0%",
        justifyContent: "center",
        paddingBlock: "5px",
        paddingInline: "10px",
        border: "none",
        cursor: "pointer",
        transition: "background-color 0.2s ease-out",
      }}
    >
      <div
        style={{
          boxSizing: "border-box",
          color: isHighlighted ? "#006BF4" : "#363635",
          fontFamily: '"Geist", system-ui, sans-serif',
          fontSize: "12px",
          fontWeight: 500,
          lineHeight: "20px",
          transition: "color 0.2s ease-out",
          ...(label === "MAX" ? { letterSpacing: "0.02em" } : {}),
        }}
      >
        {label}
      </div>
    </button>
  );
}

const sameAddress = (a?: string, b?: string) =>
  Boolean(a && b && a.toLowerCase() === b.toLowerCase());

const formatShortAddress = (address?: string) => {
  if (!address) return "";
  return address.length > 12
    ? `${address.slice(0, 6)}…${address.slice(-4)}`
    : address;
};

const formatTokenBalanceLabel = (token?: SwapTokenOption) => {
  if (!token) return "";
  const balance = String(token.balance || "0").trim() || "0";
  if (!token.symbol) return balance;
  return balance.toLowerCase().includes(token.symbol.toLowerCase())
    ? balance
    : `${balance} ${token.symbol}`;
};

/** Add asset button with smooth transition */
function AddAssetButton({
  visible,
  label,
