                    >
                      {token ? (
                        <div
                          style={{
                            boxSizing: "border-box",
                            flexShrink: 0,
                            height: "26px",
                            position: "relative" as const,
                            width: "26px",
                          }}
                        >
                          <img
                            src={token.logo}
                            alt={token.symbol}
                            style={{
                              borderRadius: "999px",
                              height: "26px",
                              width: "26px",
                              objectFit: "cover" as const,
