                          />
                          {token.chainLogo && (
                            <img
                              src={token.chainLogo}
                              alt={token.chainName}
                              style={{
                                borderRadius: "999px",
                                bottom: -2,
                                height: "12px",
                                outline: "1px solid #FFFFFE",
                                position: "absolute" as const,
                                right: -2,
                                width: "12px",
                                objectFit: "cover" as const,
