                            borderColor: "#C8C8C7",
                            borderRadius: "999px",
                            borderStyle: "dashed",
                            borderWidth: "1.5px",
                            boxSizing: "border-box",
                            flexShrink: 0,
                            height: "22px",
                            width: "22px",
                          }}
                        />
                      )}
                      <div
                        style={{
                          boxSizing: "border-box",
                          color: "#161615",
                          fontFamily: '"Geist", system-ui, sans-serif',
                          fontSize: token ? "14px" : "16px",
