                          lineHeight: token ? "18px" : "24px",
                        }}
                      >
                        {token ? token.symbol : "Assets"}
                      </div>
                      <ChevronDownIcon />
                    </button>
                    {token && (
                      <button
                        onClick={() => {
                          if (!onUpdateTokens) return;
                          const next = [...fromTokens];
                          next.splice(index, 1);
                          onUpdateTokens(next);
                          if (next.length === 0) onAmountChange("", "send");
                        }}
                        style={{
                          width: "24px",
                          height: "24px",
                          borderRadius: "999px",
                          backgroundColor: "#F0F0EF",
                          border: "none",
                          display: "flex",
                          alignItems: "center",
                          justifyContent: "center",
                          cursor: "pointer",
                          flexShrink: 0,
                        }}
                      >
                        <svg
                          width="10"
                          height="10"
                          viewBox="0 0 24 24"
                          fill="none"
                          stroke="#848483"
                          strokeWidth="2"
                          strokeLinecap="round"
                          strokeLinejoin="round"
                        >
