                  style={{
                    alignItems: "center",
                    backgroundColor: isSendCtaDisabled ? "#F0F0EF" : "#006BF4",
                    borderRadius: "8px",
                    boxSizing: "border-box",
                    display: "flex",
                    flexShrink: 0,
                    height: "48px",
                    justifyContent: "center",
                    paddingInline: "16px",
                    border: "none",
                    cursor: isSendCtaDisabled ? "default" : "pointer",
                    width: "100%",
