                  style={{
                    alignItems: "center",
                    backgroundColor: "#FFFFFE",
                    border: "1px solid #E8E8E7",
                    borderRadius: "8px",
                    cursor: "pointer",
                    display: "flex",
                    flexShrink: 0,
                    height: "32px",
                    justifyContent: "center",
                    padding: 0,
                    width: "32px",
                  }}
                >
                  <ArrowLeft style={{ color: "#161615", height: "16px", width: "16px" }} />
                </button>
                <div
                  style={{
                    color: "#161615",
                    fontFamily: '"Delight-Medium", "Delight", system-ui, sans-serif',
                    fontSize: "18px",
                    fontWeight: 500,
                    lineHeight: "24px",
                  }}
                >
                  Recipient
                </div>
              </div>
              <div
                style={{
                  backgroundColor: "#E8E8E7",
                  height: "1px",
                  marginBottom: "20px",
                  width: "100%",
                }}
              />
              <div
                style={{
                  alignItems: "center",
                  display: "flex",
                  justifyContent: "space-between",
                  marginBottom: "12px",
                }}
              >
                <div
                  style={{
                    color: "#9E9E9C",
                    fontFamily: '"Geist", system-ui, sans-serif',
                    fontSize: "13px",
                    fontWeight: 500,
                    lineHeight: "18px",
                  }}
                >
                  Wallet Address
                </div>
                {activeMode === "swap" && defaultRecipientAddress && (
                  <button
                    type="button"
                    onClick={handleResetRecipientToDefault}
                    style={{
                      backgroundColor: "#F4F7FE",
                      border: "none",
                      borderRadius: "4px",
                      color: "#006BF4",
                      cursor: "pointer",
                      fontFamily: '"Geist", system-ui, sans-serif',
                      fontSize: "12px",
                      fontWeight: 500,
                      lineHeight: "16px",
                      padding: "8px 12px",
                    }}
                  >
                    Reset to default
                  </button>
                )}
              </div>
              <RecipientInput
                value={recipientAddress}
                onChange={(next) => {
                  setRecipientAddress(next);
                  if (txError) setTxError(null);
                }}
                onClear={() => setRecipientAddress("")}
                label={null}
                placeholder="Wallet address"
                hasError={Boolean(txError)}
              />
              {txError && (
                <div
                  style={{
                    color: "#E35454",
                    fontFamily: '"Geist", system-ui, sans-serif',
                    fontSize: "13px",
                    fontWeight: 500,
                    lineHeight: "18px",
                    marginTop: "10px",
                  }}
                >
                  {txError}
                </div>
              )}
              {activeMode === "send" && (
                <div
                  style={{
                    color: "#848483",
                    fontFamily: '"Geist", system-ui, sans-serif',
                    fontSize: "13px",
                    lineHeight: "18px",
                    marginTop: "10px",
                  }}
                >
                  Recipient must be different from the connected wallet.
                </div>
              )}
              <button
                onClick={handleSaveRecipient}
                style={{
                  alignItems: "center",
                  backgroundColor: "#006BF4",
                  border: "none",
                  borderRadius: "8px",
                  boxShadow: "#5555550D 0px 1px 4px",
                  color: "#FFFFFE",
                  cursor: "pointer",
                  display: "flex",
                  fontFamily: '"Geist", system-ui, sans-serif',
                  fontSize: "16px",
                  fontWeight: 500,
                  height: "48px",
                  justifyContent: "center",
                  marginTop: "30px",
                  width: "100%",
                }}
              >
                Save
              </button>
            </div>
          </div>
        )}

      {/* Drawer: choose-swap-asset */}
      {(activeMode === "swap" ||
        activeMode === "send" ||
        activeMode === "deposit") &&
        swapStep === "choose-swap-asset" && (
          <div
            style={{
              position: "absolute",
              top: 0,
              left: 0,
              right: 0,
              bottom: 0,
              zIndex: 40,
              pointerEvents: "none",
              display: "flex",
              flexDirection: "column",
              justifyContent: "flex-end",
            }}
          >
            <div
              style={{
                position: "absolute",
                top: 0,
                left: 0,
                right: 0,
                bottom: 0,
                backgroundColor: "rgba(0,0,0,0.4)",
                pointerEvents: "auto",
                transition: "opacity 0.3s",
              }}
              onClick={() => setSwapStep("idle")}
            />
            <div
              style={{
                position: "relative",
                width: "100%",
                maxHeight: "90%",
                backgroundColor: "#FFFFFE",
                borderRadius: "24px 24px 0 0",
                display: "flex",
                flexDirection: "column",
                pointerEvents: "auto",
                boxShadow: "0 -4px 12px rgba(0,0,0,0.05)",
              }}
              className="animate-in slide-in-from-bottom-full duration-300"
            >
              <SwapAssetSelector
                title={
                  activeMode === "deposit"
                    ? "Choose payment sources"
                    : swapType === "exactIn"
                      ? "Choose assets to Swap"
                      : "Choose asset to Receive"
                }
                swapBalance={swapBalance}
                isMulti={
                  activeMode === "deposit" || swapType === "exactIn"
                }
                selectedTokens={fromTokens}
                editingAssetIndex={editingAssetIndex}
                onToggle={(token) => {
                  setFromTokens((prev) => {
                    const exists = prev.find(
                      (t) =>
                        t.contractAddress === token.contractAddress &&
                        t.chainId === token.chainId,
                    );
                    if (exists)
                      return prev.filter(
                        (t) =>
                          !(
                            t.contractAddress === token.contractAddress &&
                            t.chainId === token.chainId
                          ),
                      );
                    return [
                      ...prev,
                      {
                        ...token,
                        userAmount: prev.length === 0 ? amount : "",
                      },
                    ];
                  });
                }}
                onDone={() => setSwapStep("idle")}
                onSelect={(token) => {
                  if (activeMode === "swap" && swapType === "exactIn") {
                    setFromTokens((prev) => {
                      const next = [...prev];
                      const defaultAmount =
                        next.length === 0 ? amount : "";
                      const newToken = {
                        ...token,
                        userAmount: defaultAmount,
                      };
                      if (
                        editingAssetIndex !== null &&
                        editingAssetIndex < next.length
                      ) {
                        newToken.userAmount =
                          next[editingAssetIndex].userAmount ||
                          defaultAmount;
                        next[editingAssetIndex] = newToken;
                      } else {
                        next.push(newToken);
                      }
                      return next;
                    });
                    setSwapStep("idle");
                  } else if (
                    activeMode === "deposit" ||
                    activeMode === "send"
                  ) {
                    setFromTokens([{ ...token, userAmount: amount }]);
                    setSwapStep("idle");
                  } else {
                    setToToken(token);
                    setSwapStep("idle");
                  }
                }}
                onBack={() => setSwapStep("idle")}
              />
            </div>
          </div>
        )}

      {/* Drawer: choose-receive-asset */}
      {(activeMode === "swap" ||
        activeMode === "send" ||
        activeMode === "deposit") &&
        swapStep === "choose-receive-asset" && (
          <div
            style={{
              position: "absolute",
              top: 0,
              left: 0,
              right: 0,
              bottom: 0,
              zIndex: 40,
              pointerEvents: "none",
              display: "flex",
              flexDirection: "column",
              justifyContent: "flex-end",
            }}
          >
            <div
              style={{
                position: "absolute",
                top: 0,
                left: 0,
                right: 0,
                bottom: 0,
                backgroundColor: "rgba(0,0,0,0.4)",
                pointerEvents: "auto",
                transition: "opacity 0.3s",
              }}
              onClick={() => setSwapStep("idle")}
            />
            <div
              style={{
                position: "relative",
                width: "100%",
                maxHeight: "90%",
                backgroundColor: "#FFFFFE",
                borderRadius: "24px 24px 0 0",
                display: "flex",
                flexDirection: "column",
                pointerEvents: "auto",
                boxShadow: "0 -4px 12px rgba(0,0,0,0.05)",
                boxSizing: "border-box",
              }}
              className="animate-in slide-in-from-bottom-full duration-300"
            >
              <div style={{ padding: "16px 16px 0 16px" }}>
                <div
                  style={{
                    width: "100%",
                    display: "flex",
                    justifyContent: "center",
                    marginBottom: 16,
                  }}
                >
                  <div
                    style={{
                      width: 32,
                      height: 4,
                      borderRadius: 2,
                      backgroundColor: "#E8E8E7",
                    }}
                  />
                </div>
                <div
                  style={{
                    display: "flex",
                    alignItems: "flex-start",
                    gap: 16,
                    marginBottom: 16,
                  }}
                >
                  <button
                    onClick={() => setSwapStep("idle")}
                    style={{
                      width: 32,
                      height: 32,
                      borderRadius: 8,
                      border: "1px solid #E8E8E7",
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                      backgroundColor: "#FFFFFE",
                      cursor: "pointer",
                      flexShrink: 0,
                    }}
                  >
                    <ChevronDown
                      style={{
                        width: 16,
                        height: 16,
                        transform: "rotate(90deg)",
                      }}
                    />
                  </button>
                  <div
                    style={{ display: "flex", flexDirection: "column", gap: "8px" }}
                  >
                    <span
                      style={{
                        fontFamily: '"Geist", system-ui, sans-serif',
                        fontSize: 18,
                        fontWeight: 600,
                        color: "#161615",
                      }}
                    >
                      Choose asset to Receive
                    </span>
                    <span
                      style={{
                        fontFamily: '"Geist", system-ui, sans-serif',
                        fontSize: 13,
                        color: "#848483",
                      }}
                    >
                      Select token and chain
                    </span>
                  </div>
                </div>
              </div>
              <ReceiveAssetSelector
                onSelect={(token) => {
                  setToToken(token);
                  setSwapStep("idle");
                }}
                onBack={() => setSwapStep("idle")}
              />
            </div>
          </div>
        )}

    </div>
  );
}

