const DEFAULT_SAFETY_MARGIN = 0.01; // 1%

/**
 * Compute an amount string for fraction buttons (25%, 50%, 75%, 100%).
 *
 * @param balanceStr - user's balance as a human decimal string (e.g. "12.345") OR as base-unit integer string if `balanceIsBaseUnits` true
 * @param fraction - fraction e.g. 0.25, 0.5, 0.75, 1
 * @param decimals - token decimals (6 for USDC/USDT, 18 for ETH)
 * @param safetyMargin - 0.01 for 1% default
 * @param balanceIsBaseUnits - if true, balanceStr is already base units integer string (wei / smallest unit)
 * @returns decimal string clipped to token decimals (rounded down)
 */
export function computeAmountFromFraction(
  balanceStr: string,
  fraction: number,
  decimals: number,
  safetyMargin = DEFAULT_SAFETY_MARGIN,
  balanceIsBaseUnits = false,
): string {
  if (!balanceStr) return "0";

  // parse balance into base units (BigInt)
  const balanceUnits: bigint = balanceIsBaseUnits
    ? BigInt(balanceStr)
    : parseUnits(balanceStr, decimals);

  if (balanceUnits === BigInt(0)) return "0";

  // Use an integer precision multiplier to avoid FP issues
  const PREC = 1_000_000; // 1e6 precision for fraction & safety margin
  const safetyMul = BigInt(Math.max(0, Math.floor((1 - safetyMargin) * PREC))); // (1 - safetyMargin) * PREC
  const fractionMul = BigInt(Math.max(0, Math.floor(fraction * PREC))); // fraction * PREC

  // Apply safety margin: floor(balance * (1 - safetyMargin))
  const maxAfterSafety = (balanceUnits * safetyMul) / BigInt(PREC);

  // Apply fraction and floor: floor(maxAfterSafety * fraction)
  let desiredUnits = (maxAfterSafety * fractionMul) / BigInt(PREC);

  // Extra clamp just in case
  if (desiredUnits > balanceUnits) desiredUnits = balanceUnits;
  if (desiredUnits < BigInt(0)) desiredUnits = BigInt(0);

  // format back to human readable decimal string with token decimals (formatUnits truncates/keeps decimals)
  // formatUnits will produce exactly decimals digits if fractional part exists; we'll strip trailing zeros.
  const raw = formatUnits(desiredUnits, decimals);
  // strip trailing zeros and possible trailing dot
  return raw
    .replace(/(\.\d*?[1-9])0+$/u, "$1")
    .replace(/\.0+$/u, "")
    .replace(/^\.$/u, "0");
}

export const usdFormatter = new Intl.NumberFormat("en-US", {
  style: "currency",
  currency: "USD",
  minimumFractionDigits: 2,
  maximumFractionDigits: 2,
});

const usdFormatterPrecise = new Intl.NumberFormat("en-US", {
  style: "currency",
  currency: "USD",
  minimumFractionDigits: 3,
  maximumFractionDigits: 3,
});

/**
 * Formats USD values for UI.
 * Values between 0 and 0.001 are shown as "< $0.001".
 * Values between 0.001 and 0.01 are shown with 3 decimals.
 */
export function formatUsdForDisplay(value: number): string {
  if (!Number.isFinite(value)) return usdFormatter.format(0);
  const absValue = Math.abs(value);

  if (absValue === 0) return usdFormatter.format(0);
  if (absValue < 0.001) return "< $0.001";
  if (absValue < 0.01) {
    return usdFormatterPrecise.format(value);
  }

  return usdFormatter.format(value);
}

import type { SupportedChainsAndTokensResult } from "@avail-project/nexus-core";

const COINBASE_SPOT_API_BASE = "https://api.coinbase.com/v2/prices";
const COINBASE_EXCHANGE_RATES_API_BASE =
  "https://api.coinbase.com/v2/exchange-rates";

export const DEFAULT_COINBASE_PRICE_REQUEST_TIMEOUT_MS = 4_000;
export const USD_PEGGED_FALLBACK_RATE = 1;
export const DEFAULT_USD_PEGGED_TOKEN_SYMBOLS = [
  "USDT",
  "USDC",
  "USDS",
  "DAI",
  "USDM",
  "FDUSD",
  "BUSD",
  "TUSD",
  "PYUSD",
  "GUSD",
  "LUSD",
  "USDE",
  "USDP",
] as const;

type CoinbaseSpotPriceResponse = {
  data?: {
    amount?: string | number;
  };
};

type CoinbaseExchangeRatesResponse = {
  data?: {
    rates?: Record<string, string | number>;
  };
};

type SupportedTokenMetadata = {
  symbol?: string;
  equivalentCurrency?: string;
};

type SupportedChainMetadata = {
  tokens?: SupportedTokenMetadata[];
};

export function normalizeTokenSymbol(tokenSymbol: string): string {
  return tokenSymbol.trim().toUpperCase();
}

export function toFinitePositiveNumber(value: unknown): number | null {
  const parsed = Number.parseFloat(String(value));
  if (!Number.isFinite(parsed) || parsed <= 0) {
    return null;
  }
  return parsed;
}

export function getCoinbaseSymbolCandidates(tokenSymbol: string): string[] {
  const normalized = normalizeTokenSymbol(tokenSymbol);
  if (!normalized) return [];

  const baseSymbol = normalized.split(/[._-]/)[0] ?? normalized;
  const wrappedBase =
    baseSymbol.startsWith("W") && baseSymbol.length > 3
      ? baseSymbol.slice(1)
      : null;

  return Array.from(
    new Set(
      [normalized, baseSymbol, wrappedBase].filter(
        (symbol): symbol is string => Boolean(symbol),
      ),
    ),
  );
}

export function buildUsdPeggedSymbolSet(
  supportedChains: SupportedChainsAndTokensResult | null,
  baseSymbols: Iterable<string> = DEFAULT_USD_PEGGED_TOKEN_SYMBOLS,
): Set<string> {
  const symbolSet = new Set(baseSymbols);

  for (const chain of (supportedChains ?? []) as SupportedChainMetadata[]) {
    for (const token of chain.tokens ?? []) {
      const symbol = normalizeTokenSymbol(token.symbol ?? "");
      const equivalent = normalizeTokenSymbol(token.equivalentCurrency ?? "");
      if (!symbol) continue;

      if (equivalent && symbolSet.has(equivalent)) {
        symbolSet.add(symbol);
      }
    }
  }

  return symbolSet;
}

async function fetchJsonWithTimeout<T>(
  url: string,
  requestTimeoutMs: number,
): Promise<T | null> {
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), requestTimeoutMs);
  try {
    const response = await fetch(url, {
      signal: controller.signal,
    });
    if (!response.ok) return null;
    return (await response.json()) as T;
  } catch {
    return null;
  } finally {
    clearTimeout(timeoutId);
  }
}

export async function fetchCoinbaseUsdRate(
  tokenSymbol: string,
  requestTimeoutMs = DEFAULT_COINBASE_PRICE_REQUEST_TIMEOUT_MS,
): Promise<number | null> {
  const normalized = normalizeTokenSymbol(tokenSymbol);
  if (!normalized) return null;

  for (const candidate of getCoinbaseSymbolCandidates(normalized)) {
    const spotBody = await fetchJsonWithTimeout<CoinbaseSpotPriceResponse>(
      `${COINBASE_SPOT_API_BASE}/${encodeURIComponent(candidate)}-USD/spot`,
      requestTimeoutMs,
    );
    const spotAmount = toFinitePositiveNumber(spotBody?.data?.amount);
    if (spotAmount) return spotAmount;

    const exchangeRatesBody =
      await fetchJsonWithTimeout<CoinbaseExchangeRatesResponse>(
        `${COINBASE_EXCHANGE_RATES_API_BASE}?currency=${encodeURIComponent(candidate)}`,
        requestTimeoutMs,
      );
    const exchangeRatesAmount = toFinitePositiveNumber(
      exchangeRatesBody?.data?.rates?.USD,
    );
    if (exchangeRatesAmount) return exchangeRatesAmount;
  }

  return null;
}

